SET NOCOUNT ON;

DROP TABLE IF EXISTS #program;

CREATE TABLE #program ( [EducationOrganizationId] int, [ProgramName] nvarchar(60), [ProgramTypeCodeValue] nvarchar(50), [ProgramTypeNamespace] nvarchar(255) )

;WITH program AS 
(
	SELECT 
		p.EducationOrganizationId,
		p.ProgramName,
		pd.ProgramTypeDescriptorId
	FROM #program p
	JOIN edfi.Descriptor d 
		ON p.ProgramTypeCodeValue = d.CodeValue
		AND p.ProgramTypeNamespace = d.Namespace
	JOIN edfi.EducationOrganization eo
		ON eo.EducationOrganizationId = p.EducationOrganizationId
	JOIN edfi.ProgramTypeDescriptor pd
		ON pd.ProgramTypeDescriptorId = d.DescriptorId
)
MERGE edfi.Program AS tgt 
USING program AS src 
	ON tgt.EducationOrganizationId = src.EducationOrganizationId
	AND tgt.ProgramName = src.ProgramName
	AND tgt.ProgramTypeDescriptorId = src.ProgramTypeDescriptorId
WHEN NOT MATCHED THEN 
	INSERT(EducationOrganizationId, ProgramName, ProgramTypeDescriptorId)
	VALUES (src.EducationOrganizationId, src.ProgramName, src.ProgramTypeDescriptorId)
;


DROP TABLE #program